+fn normalize_sequence_display_text(text: &str) -> String {
+    let with_line_breaks = text
+        .trim()
+        .replace("<br/>", "\n")
+        .replace("<br>", "\n")
+        .replace("<br />", "\n");
+    decode_mermaid_entities(&with_line_breaks)
+}
